	// Calculate the sum of digits
	digitSum := 0
	for _, c := range nStr {
		digitSum += int(c - '0')
	}

	// Calculate the product of digits
	digitProduct := 1
	for _, c := range nStr {
		digitProduct *= int(c - '0')
	}

	// Check if n is divisible by the sum of the digits and the product of the digits
	total := digitSum + digitProduct
	if total == 0 {
		return true
	}
	return n%int64(total) == 0
}
